☕ Perfecto Somx, tengo toda la data del esquema. El componente "Cierre del Día" lo adapto al contexto de **flujo_efectivo** usando `bitacora` como tabla de movimientos, `accionistas` como sucursales y `tipo_pago` para el breakdown de formas de pago.

Entrego los 3 archivos del módulo:

```js
// @file: src/js/components/daily-close.js
(function ($) {
    $.fn.dailyClose = function (options) {
        const defaults = {
            url: '',
            accionista: 0,
            date: '',
            onOpenShift: null,
            onCloseShift: null,
            onPrintTicket: null,
            onCloseDay: null
        };
        const settings = Object.assign({}, defaults, options);

        const self = this;
        let modalRef = null;
        let selectedAccionista = settings.accionista;
        let selectedDate = settings.date;
        let selectedShift = '';
        let reportMode = 'summary';

        const svg = {
            calendar: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-5 h-5 text-white"><path d="M8 2v4"></path><path d="M16 2v4"></path><rect width="18" height="18" x="3" y="4" rx="2"></rect><path d="M3 10h18"></path></svg>',
            calendarSm: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-[18px] h-[18px]"><path d="M8 2v4"></path><path d="M16 2v4"></path><rect width="18" height="18" x="3" y="4" rx="2"></rect><path d="M3 10h18"></path></svg>',
            plus: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-4 h-4"><circle cx="12" cy="12" r="10"></circle><path d="M8 12h8"></path><path d="M12 8v8"></path></svg>',
            lock: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-4 h-4"><rect width="18" height="11" x="3" y="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>',
            printer: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-4 h-4"><path d="M6 9V2h12v7"></path><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><rect width="12" height="8" x="6" y="14"></rect></svg>',
            check: '<svg class="w-4 h-4 text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7"></path></svg>',
            checkDouble: '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-4 h-4"><path d="M18 6 7 17l-5-5"></path><path d="m22 10-7.5 7.5L13 16"></path></svg>',
            close: '<svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"></path></svg>'
        };

        function fetchData(action, data) {
            return $.ajax({
                url: settings.url,
                type: 'POST',
                data: Object.assign({ action }, data),
                dataType: 'json'
            });
        }

        function buildSidebar(sucursales) {
            const sucOptions = sucursales.map(s =>
                `<option value="${s.idAccionista}"${s.idAccionista == selectedAccionista ? ' selected' : ''}>${s.Accionista}</option>`
            ).join('');

            return `
                <div class="w-full lg:w-[280px] flex-shrink-0 space-y-4">
                    <div class="grid grid-cols-2 md:grid-cols-1 gap-3">
                        <div>
                            <label class="block text-[11px] font-medium uppercase tracking-wider text-gray-500 mb-1">Sucursal</label>
                            <select id="subsidiariesDailyClose" class="cs-select w-full text-sm" onchange="$('#${self[0].id}').dailyClose('changeAccionista', this.value)">
                                ${sucOptions}
                            </select>
                        </div>
                        <div id="dateFieldWrapper">
                            <label class="block text-[11px] font-medium uppercase tracking-wider text-gray-500 mb-1">Fecha</label>
                            <div class="relative">
                                <input type="text" id="calendarDailyClose"
                                       class="cs-input w-full pl-3 pr-9 py-2 text-sm cursor-pointer"
                                       readonly placeholder="Fecha"
                                       value="${selectedDate}">
                                <span class="absolute inset-y-0 right-0 flex items-center pr-3 text-gray-300 pointer-events-none">
                                    ${svg.calendarSm}
                                </span>
                            </div>
                        </div>
                    </div>
                    <div id="openShiftsAlert" class="hidden"></div>
                    <div>
                        <label class="block text-[11px] font-medium uppercase tracking-wider text-gray-500 mb-1">Seleccionar turno</label>
                        <select id="shiftSelector" class="cs-select w-full text-sm" onchange="$('#${self[0].id}').dailyClose('changeShift', this.value)">
                            <option value="">-- Cerrar turno --</option>
                        </select>
                    </div>
                    <div class="grid grid-cols-3 md:grid-cols-1 gap-2 mt-2">
                        <button id="btnOpenShift" class="cs-btn cs-btn-success py-2.5 text-xs md:text-sm flex flex-col md:flex-row items-center justify-center gap-1 md:gap-2 opacity-50 cursor-not-allowed" disabled>
                            ${svg.plus}
                            <span>Abrir<span class="hidden md:inline"> Turno</span></span>
                        </button>
                        <button id="btnCloseShift" class="cs-btn cs-btn-secondary py-2.5 text-xs md:text-sm flex flex-col md:flex-row items-center justify-center gap-1 md:gap-2 opacity-50 cursor-not-allowed" disabled>
                            ${svg.lock}
                            <span>Cerrar<span class="hidden md:inline"> Turno</span></span>
                        </button>
                        <button id="btnPrintTicket" class="cs-btn cs-btn-primary py-2.5 text-xs md:text-sm flex flex-col md:flex-row items-center justify-center gap-1 md:gap-2 opacity-50 cursor-not-allowed" disabled>
                            ${svg.printer}
                            <span>Imprimir<span class="hidden md:inline"> Ticket</span></span>
                        </button>
                    </div>
                    <div class="border-t border-[#374151] pt-2 mt-2 space-y-2">
                        <button id="btnCerrarDia" class="cs-btn cs-btn-danger w-full py-2.5 text-sm flex items-center justify-center gap-2 opacity-50 cursor-not-allowed" disabled>
                            ${svg.checkDouble}
                            Cerrar Dia
                        </button>
                    </div>
                </div>`;
        }

        function buildTicketPreview(data) {
            const kpis = data.kpis || { ventas: '-', pedidos: 0, turnos: 0 };
            const items = data.checklist || [];

            const kpiHtml = `
                <div class="grid grid-cols-3 gap-3 mb-3">
                    <div class="bg-[#1a2332] rounded-lg p-3 text-center border border-gray-700/50">
                        <p class="text-lg font-bold text-green-400">${kpis.ventas}</p>
                        <p class="text-[10px] text-gray-500">Ingresos</p>
                    </div>
                    <div class="bg-[#1a2332] rounded-lg p-3 text-center border border-gray-700/50">
                        <p class="text-lg font-bold text-white">${kpis.egresos}</p>
                        <p class="text-[10px] text-gray-500">Egresos</p>
                    </div>
                    <div class="bg-[#1a2332] rounded-lg p-3 text-center border border-gray-700/50">
                        <p class="text-lg font-bold text-white">${kpis.movimientos}</p>
                        <p class="text-[10px] text-gray-500">Movimientos</p>
                    </div>
                </div>`;

            const checklistHtml = items.map(item => {
                const borderClass = item.ok ? 'border-green-600/30' : 'border-red-500/30';
                const iconBg = item.ok ? 'bg-green-600/20' : 'bg-red-500/20';
                const iconColor = item.ok ? 'text-green-400' : 'text-red-400';
                const iconSvg = item.ok
                    ? svg.check
                    : '<svg class="w-4 h-4 text-red-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>';

                return `
                    <div class="flex items-center gap-3 bg-[#1a2332] rounded-lg p-3 border ${borderClass}">
                        <div class="w-7 h-7 rounded-full ${iconBg} flex items-center justify-center flex-shrink-0">${iconSvg}</div>
                        <div class="flex-1">
                            <p class="text-sm font-semibold text-white">${item.title}</p>
                            <p class="text-[11px] text-gray-500">${item.detail || ''}</p>
                        </div>
                    </div>`;
            }).join('');

            const sucursalName = data.sucursalName || '';
            const dateStr = data.dateStr || selectedDate;

            return `
                <div class="flex-1 relative">
                    <div id="ticketPreview" class="relative lg:absolute lg:inset-0 w-full min-h-[420px] lg:min-h-0 bg-[#151d2a] rounded-lg p-4 overflow-y-auto">
                        <div id="ticketModeBar" class="flex items-center justify-between mb-3 gap-3 ${data.hasShift ? '' : 'hidden'}">
                            <p class="text-xs text-gray-500">Vista previa de impresión</p>
                            <div class="inline-flex items-center gap-1 bg-[#1a2332] p-1 rounded-lg border border-gray-700/50 text-[11px] flex-shrink-0">
                                <button id="btnModeSummary" class="px-3 py-1 rounded-md font-semibold transition-all ${reportMode === 'summary' ? 'bg-purple-600 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}" onclick="$('#${self[0].id}').dailyClose('toggleMode', 'summary')">Resumido</button>
                                <button id="btnModeDetailed" class="px-3 py-1 rounded-md font-semibold transition-all ${reportMode === 'detailed' ? 'bg-purple-600 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}" onclick="$('#${self[0].id}').dailyClose('toggleMode', 'detailed')">Detallado</button>
                            </div>
                        </div>
                        <div id="ticketContainer">
                            <h2 class="text-base font-bold text-white mb-1">Checklist de Cierre</h2>
                            <p class="text-xs text-gray-500 mb-4">${sucursalName} — ${dateStr}</p>
                            ${kpiHtml}
                            <div class="space-y-2.5 mb-6">${checklistHtml}</div>
                            <div class="flex gap-3">
                                <button class="cs-btn cs-btn-outline flex-1 py-2 text-sm" onclick="$('#${self[0].id}').dailyClose('cancelChecklist')">Cancelar</button>
                                <button class="cs-btn cs-btn-danger flex-1 py-2 text-sm" onclick="$('#${self[0].id}').dailyClose('confirmClose', '${selectedDate}', '${selectedAccionista}')">Confirmar Cierre</button>
                            </div>
                        </div>
                    </div>
                </div>`;
        }

        function buildModal(sucursales, data) {
            const sidebar = buildSidebar(sucursales);
            const ticket = buildTicketPreview(data);

            return `
                <div class="flex flex-col lg:flex-row gap-4 lg:min-h-[480px]">
                    ${sidebar}
                    ${ticket}
                </div>`;
        }

        function loadDailyData() {
            fetchData('showDailyClose', {
                accionista: selectedAccionista,
                date: selectedDate
            }).then(function (resp) {
                if (resp && resp.status) {
                    renderTicket(resp.data);
                    renderShifts(resp.data.shifts || []);
                    toggleButtons(resp.data);
                }
            });
        }

        function renderTicket(data) {
            const ticketHtml = buildTicketPreview(data);
            modalRef.find('.flex-1').replaceWith(ticketHtml);
        }

        function renderShifts(shifts) {
            const $sel = modalRef.find('#shiftSelector');
            let opts = '<option value="">-- Cerrar turno --</option>';
            shifts.forEach(function (s) {
                const label = s.status === 'closed' ? `${s.label} [CERRADO]` : s.label;
                opts += `<option value="${s.id}" data-status="${s.status}">${label}</option>`;
            });
            $sel.html(opts);
        }

        function toggleButtons(data) {
            const $btnOpen = modalRef.find('#btnOpenShift');
            const $btnClose = modalRef.find('#btnCloseShift');
            const $btnPrint = modalRef.find('#btnPrintTicket');
            const $btnCerrarDia = modalRef.find('#btnCerrarDia');

            const hasOpenShift = data.hasOpenShift;
            const hasClosedShift = data.hasClosedShift;
            const canClose = data.canCloseDay;

            function enable($btn) {
                $btn.removeClass('opacity-50 cursor-not-allowed').prop('disabled', false);
            }
            function disable($btn) {
                $btn.addClass('opacity-50 cursor-not-allowed').prop('disabled', true);
            }

            hasOpenShift ? disable($btnOpen) : enable($btnOpen);
            hasOpenShift ? enable($btnClose) : disable($btnClose);
            hasClosedShift ? enable($btnPrint) : disable($btnPrint);
            canClose ? enable($btnCerrarDia) : disable($btnCerrarDia);
        }

        function openModal(sucursales, initData) {
            const content = buildModal(sucursales, initData);
            modalRef = bootbox.dialog({
                title: `<div class="flex items-center gap-3">
                    <div class="w-10 h-10 bg-purple-600 rounded-lg flex items-center justify-center">${svg.calendar}</div>
                    <span class="text-lg font-bold text-white">Cierre del Día</span>
                </div>`,
                message: content,
                size: 'large',
                closeButton: true,
                className: 'bg-[#1F2A37]',
                onEscape: true
            });
            modalRef.find('.modal-content').addClass('bg-[#1F2A37]');
            modalRef.find('.modal-body').addClass('p-4');
            wireEvents();
        }

        function wireEvents() {
            modalRef.find('#btnOpenShift').off('click').on('click', function () {
                if ($(this).prop('disabled')) return;
                fetchData('addShift', {
                    accionista: selectedAccionista,
                    date: selectedDate
                }).then(function (resp) {
                    if (resp && resp.status) loadDailyData();
                });
            });

            modalRef.find('#btnCloseShift').off('click').on('click', function () {
                if ($(this).prop('disabled')) return;
                fetchData('statusShift', {
                    accionista: selectedAccionista,
                    date: selectedDate,
                    shiftId: selectedShift
                }).then(function (resp) {
                    if (resp && resp.status) loadDailyData();
                });
            });

            modalRef.find('#btnPrintTicket').off('click').on('click', function () {
                if ($(this).prop('disabled')) return;
                if (settings.onPrintTicket) settings.onPrintTicket(selectedAccionista, selectedDate);
            });

            modalRef.find('#btnCerrarDia').off('click').on('click', function () {
                if ($(this).prop('disabled')) return;
                if (settings.onCloseDay) settings.onCloseDay(selectedAccionista, selectedDate);
            });

            modalRef.find('#calendarDailyClose').daterangepicker({
                singleDatePicker: true,
                autoApply: true,
                locale: { format: 'YYYY-MM-DD' },
                startDate: selectedDate || moment().format('YYYY-MM-DD')
            }, function (start) {
                selectedDate = start.format('YYYY-MM-DD');
                loadDailyData();
            });
        }

        if (typeof options === 'string') {
            const action = options;
            const args = Array.prototype.slice.call(arguments, 1);
            switch (action) {
                case 'changeAccionista':
                    selectedAccionista = args[0];
                    loadDailyData();
                    break;
                case 'changeShift':
                    selectedShift = args[0];
                    break;
                case 'toggleMode':
                    reportMode = args[0];
                    modalRef.find('#btnModeSummary').toggleClass('bg-purple-600 text-white shadow-sm', reportMode === 'summary').toggleClass('text-gray-400', reportMode !== 'summary');
                    modalRef.find('#btnModeDetailed').toggleClass('bg-purple-600 text-white shadow-sm', reportMode === 'detailed').toggleClass('text-gray-400', reportMode !== 'detailed');
                    break;
                case 'cancelChecklist':
                    modalRef.modal('hide');
                    break;
                case 'confirmClose':
                    fetchData('cancelDailyClose', {
                        accionista: args[1],
                        date: args[0]
                    }).then(function (resp) {
                        if (resp && resp.status) {
                            modalRef.modal('hide');
                            if (settings.onCloseDay) settings.onCloseDay(args[1], args[0]);
                        }
                    });
                    break;
            }
            return self;
        }

        fetchData('init', {}).then(function (resp) {
            if (resp && resp.status) {
                selectedAccionista = selectedAccionista || resp.data.sucursales[0].idAccionista;
                selectedDate = selectedDate || moment().format('YYYY-MM-DD');
                openModal(resp.data.sucursales, resp.data.initData || { kpis: { ventas: '-', egresos: '-', movimientos: 0 }, checklist: [] });
                loadDailyData();
            }
        });

        return self;
    };
})(jQuery);
