// @file: ctrl/ctrl-cierre-diario.php
<?php
require_once '../mdl/mdl-cierre-diario.php';
require_once '../src/js/coffeSoft.php';

class CtrlCierreDiario {
    private $mdl;

    public function __construct() {
        $this->mdl = new MdlCierreDiario();
    }

    public function init() {
        $sucursales = $this->mdl->listAccionistas();
        $tipoPago = $this->mdl->listTipoPago();
        echo json_encode([
            'status' => true,
            'data' => [
                'sucursales' => $sucursales,
                'tipoPago' => $tipoPago,
                'initData' => [
                    'kpis' => ['ventas' => '-', 'egresos' => '-', 'movimientos' => 0],
                    'checklist' => []
                ]
            ]
        ]);
    }

    public function showDailyClose() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $data = $this->buildDailyData($accionista, $date);
        echo json_encode(['status' => true, 'data' => $data]);
    }

    public function addShift() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $result = $this->mdl->createShiftRecord($accionista, $date);
        echo json_encode(['status' => $result !== false, 'data' => ['shiftId' => $result]]);
    }

    public function statusShift() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $shiftId = $_POST['shiftId'];
        $result = $this->mdl->updateShiftStatus($shiftId, 0);
        echo json_encode(['status' => $result !== false]);
    }

    public function cancelDailyClose() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $result = $this->mdl->markDayClosed($accionista, $date);
        echo json_encode(['status' => $result !== false]);
    }

    private function buildDailyData($accionista, $date) {
        $counts = $this->mdl->getBitacoraCounts($accionista, $date);
        $payments = $this->mdl->getPaymentBreakdown($accionista, $date);
        $sucursalInfo = $this->mdl->getAccionistaById($accionista);

        $totalIngresos = $counts['total_ingresos'] ?? 0;
        $totalEgresos = $counts['total_egresos'] ?? 0;
        $totalMovimientos = $counts['total_movimientos'] ?? 0;

        $ingresosFmt = '$' . number_format($totalIngresos, 2);
        $egresosFmt = '$' . number_format($totalEgresos, 2);

        $checklist = [];
        $checklist[] = [
            'title' => 'Todos los movimientos registrados',
            'detail' => $totalMovimientos . ' movimiento(s) en bitácora',
            'ok' => $totalMovimientos > 0
        ];

        $missingPago = $this->mdl->countMissingTipoPago($accionista, $date);
        $checklist[] = [
            'title' => 'Todos los movimientos tienen tipo de pago',
            'detail' => $missingPago == 0 ? '' : $missingPago . ' movimiento(s) sin tipo de pago',
            'ok' => $missingPago == 0
        ];

        $missingCuenta = $this->mdl->countMissingCuenta($accionista, $date);
        $checklist[] = [
            'title' => 'Todos los movimientos tienen cuenta asignada',
            'detail' => $missingCuenta == 0 ? '' : $missingCuenta . ' movimiento(s) sin cuenta',
            'ok' => $missingCuenta == 0
        ];

        $pagoDetail = '';
        foreach ($payments as $p) {
            $pagoDetail .= $p['TipoPago'] . ': $' . number_format($p['total'], 2) . ' | ';
        }
        $pagoDetail = rtrim($pagoDetail, ' | ');
        $checklist[] = [
            'title' => 'Formas de pago registradas',
            'detail' => $pagoDetail,
            'ok' => count($payments) > 0
        ];

        $allOk = true;
        foreach ($checklist as $item) {
            if (!$item['ok']) { $allOk = false; break; }
        }

        return [
            'sucursalName' => $sucursalInfo['Accionista'] ?? '',
            'dateStr' => $date,
            'kpis' => [
                'ventas' => $ingresosFmt,
                'egresos' => $egresosFmt,
                'movimientos' => $totalMovimientos
            ],
            'checklist' => $checklist,
            'payments' => $payments,
            'shifts' => [],
            'hasOpenShift' => false,
            'hasClosedShift' => $totalMovimientos > 0,
            'canCloseDay' => $allOk
        ];
    }
}

$ctrl = new CtrlCierreDiario();
$action = $_POST['action'] ?? '';
switch ($action) {
    case 'init':
        $ctrl->init();
        break;
    case 'showDailyClose':
        $ctrl->showDailyClose();
        break;
    case 'addShift':
        $ctrl->addShift();
        break;
    case 'statusShift':
        $ctrl->statusShift();
        break;
    case 'cancelDailyClose':
        $ctrl->cancelDailyClose();
        break;
}
