            body: `action=ls&date=${date}&tipoMov=${tipoMov}&tipoPago=${tipoPago}&accionista=${this.selectedAccionista}`
        })
            .then(r => r.json())
            .then(resp => {
                if (resp.status) {
                    this.renderShiftAlert(resp.data.hasOpenShift);
                    const tbody = $('#tbFlujoEfectivo tbody');
                    if (resp.data.rows.length === 0) {
                        tbody.html(`<tr><td colspan="9" class="text-center text-gray-500 py-4">No hay movimientos registrados</td></tr>`);
