                        const ingreso = r.Ingreso > 0 ? `$${Number(r.Ingreso).toLocaleString('es-MX', {minimumFractionDigits: 2})}` : '-';
                        const egreso = r.Egreso > 0 ? `$${Number(r.Egreso).toLocaleString('es-MX', {minimumFractionDigits: 2})}` : '-';
