    onDailyCloseFilterChange() {
        this.selectedAccionista = $('#subsidiariesDailyClose').val();
        this.selectedDate = $('#calendarDailyClose').val() || this.selectedDate;
        fetch(this.url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: `action=showDailyClose&accionista=${this.selectedAccionista}&date=${this.selectedDate}`
        })
            .then(r => r.json())
