    refreshDailyCloseContent(data) {
        const kpis = data.kpis || { ventas: '-', egresos: '-', movimientos: 0 };
        const checklist = data.checklist || [];
        const sucursalName = data.sucursalName || '';
        const dateStr = data.dateStr || this.selectedDate;

        const $container = this.dailyCloseModal.find('#ticketContainer');
        const checklistHtml = checklist.map(item => {
            const borderClass = item.ok ? 'border-green-600/30' : 'border-red-500/30';
