                <div class="bg-[#1a2332] rounded-lg p-3 text-center border border-gray-700/50">
                    <p class="text-lg font-bold text-white">${kpis.movimientos}</p>
                    <p class="text-[10px] text-gray-500">Movimientos</p>
                </div>
            </div>
            <div class="space-y-2.5 mb-6">${checklistHtml}</div>
            <div class="flex gap-3">
                <button class="cs-btn cs-btn-outline flex-1 py-2 text-sm" onclick="app.cancelChecklist()">Cancelar</button>
                <button class="cs-btn cs-btn-danger flex-1 py-2 text-sm" onclick="app.confirmClose('${this.selectedDate}', '${this.selectedAccionista}')">Confirmar Cierre</button>
            </div>
        `);

        this.toggleButtonsState(data);
    }

    toggleButtonsState(data) {
        const $m = this.dailyCloseModal;
        const $btnOpen = $m.find('#btnOpenShift');
        const $btnClose = $m.find('#btnCloseShift');
        const $btnPrint = $m.find('#btnPrintTicket');
        const $btnCerrarDia = $m.find('#btnCerrarDia');

        const enable = ($btn) => $btn.removeClass('opacity-50 cursor-not-allowed').prop('disabled', false);
        const disable = ($btn) => $btn.addClass('opacity-50 cursor-not-allowed').prop('disabled', true);

        data.hasOpenShift ? disable($btnOpen) : enable($btnOpen);
        data.hasOpenShift ? enable($btnClose) : disable($btnClose);
        data.hasClosedShift ? enable($btnPrint) : disable($btnPrint);
        data.canCloseDay ? enable($btnCerrarDia) : disable($btnCerrarDia);
    }

    viewShiftPreview() {
        this.selectedShift = $('#shiftSelector').val();
    }

