```php
// @file: ctrl/ctrl-flujo-efectivo.php
<?php
require_once '../mdl/mdl-flujo-efectivo.php';
require_once '../src/js/coffeSoft.php';

class CtrlFlujoEfectivo {
    private $mdl;

    public function __construct() {
        $this->mdl = new MdlFlujoEfectivo();
    }

    public function init() {
        $sucursales = $this->mdl->listAccionistas();
        $tipoPago = $this->mdl->listTipoPago();
        $cuentas = $this->mdl->listCuentas();
        $accionistaDefault = $sucursales[0]['idAccionista'];
        $accionistaName = $sucursales[0]['Accionista'];

        echo json_encode([
            'status' => true,
            'data' => [
                'sucursales' => $sucursales,
                'tipoPago' => $tipoPago,
                'cuentas' => $cuentas,
                'accionista_default' => $accionistaDefault,
                'accionista_name' => $accionistaName
            ]
        ]);
    }

    public function ls() {
        $date = $_POST['date'];
        $tipoMov = $_POST['tipoMov'];
        $tipoPago = $_POST['tipoPago'];
        $accionista = $_POST['accionista'];

        $rows = $this->mdl->listBitacora($accionista, $date, $tipoMov, $tipoPago);
        $hasOpenShift = $this->mdl->hasOpenShift($accionista, $date);

        echo json_encode([
            'status' => true,
            'data' => [
                'rows' => $rows,
                'hasOpenShift' => $hasOpenShift
            ]
        ]);
    }

    public function showDailyClose() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $data = $this->buildDailyData($accionista, $date);
        $data['sucursales'] = $this->mdl->listAccionistas();
        echo json_encode(['status' => true, 'data' => $data]);
    }

    public function addShift() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $result = $this->mdl->createShiftRecord($accionista, $date);
        echo json_encode(['status' => $result !== false]);
    }

    public function statusShift() {
        $shiftId = $_POST['shiftId'];
        $result = $this->mdl->updateShiftStatus($shiftId, 2);
        echo json_encode(['status' => $result !== false]);
    }

    public function cancelDailyClose() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $result = $this->mdl->markDayClosed($accionista, $date);
        echo json_encode(['status' => $result !== false]);
    }

    public function printTicket() {
        $accionista = $_POST['accionista'];
        $date = $_POST['date'];
        $mode = $_POST['mode'];
        $data = $this->buildDailyData($accionista, $date);
        $html = $this->buildTicketHtml($data, $mode);
        echo json_encode(['status' => true, 'data' => ['html' => $html]]);
    }

    public function getMovimiento() {
        $id = $_POST['id'];
        $row = $this->mdl->getBitacoraById($id);
        echo json_encode(['status' => $row !== false, 'data' => $row]);
    }

    public function addMovimiento() {
        $accionista = $_POST['accionista'];
        $cuenta = $_POST['cuenta'];
        $tipoPago = $_POST['tipoPago'];
        $fecha = $_POST['fecha'];
        $detalles = $_POST['detalles'];
        $ingreso = $_POST['ingreso'];
        $egreso = $_POST['egreso'];

        $result = $this->mdl->createBitacora([
            'id_Accionistas' => $accionista,
            'id_TipoPago' => $tipoPago,
            'id_Cuenta' => $cuenta,
            'Detalles' => $detalles,
            'Ingreso' => $ingreso,
            'Egreso' => $egreso,
            'Fecha_Bitacora' => $fecha,
            'Stado' => 1
        ]);
        echo json_encode(['status' => $result !== false]);
    }

    public function editMovimiento() {
        $id = $_POST['id'];
        $accionista = $_POST['accionista'];
        $cuenta = $_POST['cuenta'];
        $tipoPago = $_POST['tipoPago'];
        $fecha = $_POST['fecha'];
        $detalles = $_POST['detalles'];
        $ingreso = $_POST['ingreso'];
        $egreso = $_POST['egreso'];

        $result = $this->mdl->updateBitacora($id, [
            'id_Accionistas' => $accionista,
            'id_TipoPago' => $tipoPago,
            'id_Cuenta' => $cuenta,
            'Detalles' => $detalles,
            'Ingreso' => $ingreso,
            'Egreso' => $egreso,
            'Fecha_Bitacora' => $fecha
        ]);
        echo json_encode(['status' => $result !== false]);
    }

    private function buildDailyData($accionista, $date) {
        $counts = $this->mdl->getBitacoraCounts($accionista, $date);
        $payments = $this->mdl->getPaymentBreakdown($accionista, $date);
        $sucursalInfo = $this->mdl->getAccionistaById($accionista);
        $hasOpen = $this->mdl->hasOpenShift($accionista, $date);
        $closedShifts = $this->mdl->getClosedShifts($accionista, $date);

        $totalIngresos = $counts['total_ingresos'] ?? 0;
        $totalEgresos = $counts['total_egresos'] ?? 0;
        $totalMovimientos = $counts['total_movimientos'] ?? 0;

        $ingresosFmt = '$' . number_format($totalIngresos, 2);
        $egresosFmt = '$' . number_format($totalEgresos, 2);

        $checklist = [];
        $checklist[] = [
            'title' => 'Todos los movimientos registrados',
            'detail' => $totalMovimientos . ' movimiento(s) en bitácora',
            'ok' => $totalMovimientos > 0
        ];

        $missingPago = $this->mdl->countMissingTipoPago($accionista, $date);
        $checklist[] = [
            'title' => 'Todos los movimientos tienen tipo de pago',
            'detail' => $missingPago == 0 ? '' : $missingPago . ' movimiento(s) sin tipo de pago',
            'ok' => $missingPago == 0
        ];

        $missingCuenta = $this->mdl->countMissingCuenta($accionista, $date);
        $checklist[] = [
            'title' => 'Todos los movimientos tienen cuenta asignada',
            'detail' => $missingCuenta == 0 ? '' : $missingCuenta . ' movimiento(s) sin cuenta',
            'ok' => $missingCuenta == 0
        ];

        $pagoDetail = '';
        foreach ($payments as $p) {
            $pagoDetail .= $p['TipoPago'] . ': $' . number_format($p['total'], 2) . ' | ';
        }
        $pagoDetail = rtrim($pagoDetail, ' | ');
        $checklist[] = [
            'title' => 'Formas de pago registradas',
            'detail' => $pagoDetail,
            'ok' => count($payments) > 0
        ];

        $allOk = true;
        foreach ($checklist as $item) {
            if (!$item['ok']) { $allOk = false; break; }
        }

        $shifts = [];
        foreach ($closedShifts as $cs) {
            $shifts[] = [
                'id' => $cs['idBitacora'],
                'label' => $cs['Fecha_Bitacora'] . ' ' . ($cs['Detalles'] ?? ''),
                'status' => $cs['Stado'] == 2 ? 'closed' : 'open'
            ];
        }

        return [
            'sucursalName' => $sucursalInfo['Accionista'] ?? '',
            'dateStr' => $date,
            'kpis' => [
                'ventas' => $ingresosFmt,
                'egresos' => $egresosFmt,
                'movimientos' => $totalMovimientos
            ],
            'checklist' => $checklist,
            'payments' => $payments,
            'shifts' => $shifts,
            'hasOpenShift' => $hasOpen,
            'hasClosedShift' => count($closedShifts) > 0,
            'canCloseDay' => $allOk && !$hasOpen
        ];
    }

    private function buildTicketHtml($data, $mode) {
        $sucursal = $data['sucursalName'];
        $date = $data['dateStr'];
        $kpis = $data['kpis'];
        $payments = $data['payments'];

        $html = '<html><head><meta charset="UTF-8"><style>';
        $html .= 'body{font-family:Roboto Mono,monospace;width:280px;margin:0 auto;padding:10px;color:#000}';
        $html .= 'h2{text-align:center;font-size:14px;margin:0 0 5px}';
        $html .= '.info{text-align:center;font-size:11px;margin-bottom:10px}';
        $html .= '.kpi{display:flex;justify-content:space-between;font-size:11px;border-bottom:1px dashed #000;padding:3px 0}';
        $html .= '.total{font-weight:bold;font-size:13px;border-top:2px solid #000;padding-top:5px;margin-top:5px}';
        $html .= '</style></head><body>';
        $html .= '<h2>Cierre del Día</h2>';
        $html .= '<p class="info">' . $sucursal . ' — ' . $date . '</p>';
        $html .= '<div class="kpi"><span>Ingresos:</span><span>' . $kpis['ventas'] . '</span></div>';
        $html .= '<div class="kpi"><span>Egresos:</span><span>' . $kpis['egresos'] . '</span></div>';
        $html .= '<div class="kpi"><span>Movimientos:</span><span>' . $kpis['movimientos'] . '</span></div>';

        if ($mode === 'detailed') {
            $html .= '<div class="kpi total">Detalle por forma de pago</div>';
            foreach ($payments as $p) {
                $html .= '<div class="kpi"><span>' . $p['TipoPago'] . ':</span><span>$' . number_format($p['total'], 2) . '</span></div>';
            }
        }

        $neto = $data['checklist'];
        $html .= '<div class="kpi total">Checklist</div>';
        foreach ($neto as $item) {
            $icon = $item['ok'] ? '✓' : '✗';
            $html .= '<div class="kpi"><span>' . $icon . ' ' . $item['title'] . '</span></div>';
        }
        $html .= '</body></html>';
        return $html;
    }
}

