// @file: mdl/mdl-flujo-efectivo.php
<?php
require_once '_CRUD.php';
require_once '_Utileria.php';

class MdlFlujoEfectivo extends CRUD {
    public $bd;
    public $util;

    public function __construct() {
        parent::__construct();
        $this->bd = new _CRUD();
        $this->util = new _Utileria();
    }

    public function listAccionistas() {
        return $this->_Select([
            'table' => 'accionistas',
            'where' => 'Acc_Stado = :stado',
            'bind' => ['stado' => 1],
            'order' => 'Accionista ASC'
        ]);
    }

    public function listTipoPago() {
        return $this->_Select([
            'table' => 'tipo_pago',
            'where' => 'TP_Stado = :stado',
            'bind' => ['stado' => 1],
            'order' => 'TipoPago ASC'
        ]);
    }

    public function listCuentas() {
        return $this->_Select([
            'table' => 'cuenta',
            'where' => 'Cuenta_Stado = :stado',
            'bind' => ['stado' => 1],
            'order' => 'Cuenta ASC'
        ]);
    }

    public function getAccionistaById($id) {
        $result = $this->_Select([
            'table' => 'accionistas',
            'where' => 'idAccionista = :id',
            'bind' => ['id' => $id],
            'limit' => 1
        ]);
        return $result ? $result[0] : null;
    }

    public function listBitacora($accionista, $date, $tipoMov, $tipoPago) {
        $sql = "SELECT b.*, a.Accionista, c.Cuenta, tp.TipoPago
                FROM bitacora b
                INNER JOIN accionistas a ON b.id_Accionistas = a.idAccionista
                LEFT JOIN cuenta c ON b.id_Cuenta = c.idCuenta
                LEFT JOIN tipo_pago tp ON b.id_TipoPago = tp.idTipoPago
                WHERE b.Fecha_Bitacora = :fecha
                  AND b.Stado IN (1, 2)";
        $bind = ['fecha' => $date];
        if ($accionista && $accionista != 0) {
            $sql .= " AND b.id_Accionistas = :acc";
            $bind['acc'] = $accionista;
        }
        if ($tipoMov) {
            $sql .= " AND c.id_TipoMov = :tmov";
            $bind['tmov'] = $tipoMov;
        }
        if ($tipoPago) {
            $sql .= " AND b.id_TipoPago = :tp";
            $bind['tp'] = $tipoPago;
        }
        $sql .= " ORDER BY b.idBitacora DESC";
        return $this->_Read($sql, $bind);
    }

    public function getBitacoraById($id) {
        $sql = "SELECT b.*, a.Accionista, c.Cuenta, tp.TipoPago
                FROM bitacora b
                INNER JOIN accionistas a ON b.id_Accionistas = a.idAccionista
                LEFT JOIN cuenta c ON b.id_Cuenta = c.idCuenta
                LEFT JOIN tipo_pago tp ON b.id_TipoPago = tp.idTipoPago
                WHERE b.idBitacora = :id LIMIT 1";
        $result = $this->_Read($sql, ['id' => $id]);
        return $result ? $result[0] : null;
    }

    public function getBitacoraCounts($accionista, $date) {
        $sql = "SELECT
                    COUNT(*) as total_movimientos,
                    COALESCE(SUM(Ingreso), 0) as total_ingresos,
                    COALESCE(SUM(Egreso), 0) as total_egresos
                FROM bitacora
                WHERE id_Accionistas = :acc
                  AND Fecha_Bitacora = :fecha
                  AND Stado = 1";
        $result = $this->_Read($sql, [
            'acc' => $accionista,
            'fecha' => $date
        ]);
        return $result ? $result[0] : ['total_movimientos' => 0, 'total_ingresos' => 0, 'total_egresos' => 0];
    }

    public function getPaymentBreakdown($accionista, $date) {
        $sql = "SELECT
                    tp.TipoPago,
                    COALESCE(SUM(b.Ingreso), 0) as total
                FROM bitacora b
                INNER JOIN tipo_pago tp ON b.id_TipoPago = tp.idTipoPago
                WHERE b.id_Accionistas = :acc
                  AND b.Fecha_Bitacora = :fecha
                  AND b.Stado = 1
                GROUP BY tp.idTipoPago, tp.TipoPago
                ORDER BY tp.TipoPago";
        return $this->_Read($sql, [
            'acc' => $accionista,
            'fecha' => $date
        ]);
    }

    public function countMissingTipoPago($accionista, $date) {
        $sql = "SELECT COUNT(*) as total
                FROM bitacora
                WHERE id_Accionistas = :acc
                  AND Fecha_Bitacora = :fecha
                  AND Stado = 1
                  AND (id_TipoPago IS NULL OR id_TipoPago = 0)";
        $result = $this->_Read($sql, [
            'acc' => $accionista,
            'fecha' => $date
        ]);
        return $result ? (int)$result[0]['total'] : 0;
    }

    public function countMissingCuenta($accionista, $date) {
        $sql = "SELECT COUNT(*) as total
                FROM bitacora
                WHERE id_Accionistas = :acc
                  AND Fecha_Bitacora = :fecha
                  AND Stado = 1
                  AND (id_Cuenta IS NULL OR id_Cuenta = 0)";
        $result = $this->_Read($sql, [
            'acc' => $accionista,
            'fecha' => $date
        ]);
        return $result ? (int)$result[0]['total'] : 0;
    }

    public function hasOpenShift($accionista, $date) {
        $sql = "SELECT COUNT(*) as total
                FROM bitacora
                WHERE id_Accionistas = :acc
                  AND Fecha_Bitacora = :fecha
                  AND Stado = 1
                  AND Detalles LIKE '%Apertura de turno%'";
        $result = $this->_Read($sql, [
            'acc' => $accionista,
            'fecha' => $date
        ]);
        return $result ? (int)$result[0]['total'] > 0 : false;
    }

    public function getClosedShifts($accionista, $date) {
        $sql = "SELECT *
                FROM bitacora
                WHERE id_Accionistas = :acc
                  AND Fecha_Bitacora = :fecha
                  AND Stado IN (1, 2)
                  AND Detalles LIKE '%turno%'
                ORDER BY idBitacora DESC";
        return $this->_Read($sql, [
            'acc' => $accionista,
            'fecha' => $date
        ]);
    }

    public function createBitacora($data) {
        return $this->_Insert([
            'table' => 'bitacora',
            'columns' => $data
        ]);
    }

    public function createShiftRecord($accionista, $date) {
        return $this->_Insert([
            'table' => 'bitacora',
            'columns' => [
                'id_Accionistas' => $accionista,
                'id_TipoPago' => 1,
                'id_Cuenta' => 4,
                'Detalles' => 'Apertura de turno - ' . $date,
                'Ingreso' => 0,
                'Egreso' => 0,
                'Fecha_Bitacora' => $date,
                'Stado' => 1
            ]
        ]);
    }

    public function updateBitacora($id, $data) {
        return $this->_Update([
            'table' => 'bitacora',
            'columns' => $data,
            'where' => 'idBitacora = :id',
            'bind' => ['id' => $id]
        ]);
    }

    public function updateShiftStatus($shiftId, $status) {
        return $this->_Update([
            'table' => 'bitacora',
            'columns' => ['Stado' => $status],
            'where' => 'idBitacora = :id',
            'bind' => ['id' => $shiftId]
        ]);
    }

    public function markDayClosed($accionista, $date) {
        return $this->_Update([
            'table' => 'bitacora',
            'columns' => ['Stado' => 2],
            'where' => 'id_Accionistas = :acc AND Fecha_Bitacora = :fecha AND Stado = 1',
            'bind' => ['acc' => $accionista, 'fecha' => $date]
        ]);
    }
